public void parse(String str) throws TBXMLException {
        jniFree(this.document);
        long jJniParse = jniParse(str.getBytes());
        this.document = jJniParse;
        if (jJniParse == 0) {
            throw new TBXMLException("Invalid document handle");
        }
    }
